// ── IndexedDB Layer ──────────────────────────────────────────────────────────
// Stores:
//   programs      – workout programs generated by AI
//   workoutLogs   – actual sessions logged by user
//   settings      – api key, schedule map, active program id

const DB_NAME = 'gymTracker';
const DB_VERSION = 1;

let _db = null;

function openDB() {
  if (_db) return Promise.resolve(_db);
  return new Promise((resolve, reject) => {
    const req = indexedDB.open(DB_NAME, DB_VERSION);
    req.onupgradeneeded = e => {
      const db = e.target.result;
      if (!db.objectStoreNames.contains('programs')) {
        db.createObjectStore('programs', { keyPath: 'id' });
      }
      if (!db.objectStoreNames.contains('workoutLogs')) {
        const ws = db.createObjectStore('workoutLogs', { keyPath: 'id' });
        ws.createIndex('date', 'date');
        ws.createIndex('programDayId', 'programDayId');
      }
      if (!db.objectStoreNames.contains('settings')) {
        db.createObjectStore('settings', { keyPath: 'key' });
      }
    };
    req.onsuccess = e => { _db = e.target.result; resolve(_db); };
    req.onerror = e => reject(e.target.error);
  });
}

function tx(store, mode, fn) {
  return openDB().then(db => new Promise((resolve, reject) => {
    const t = db.transaction(store, mode);
    t.onerror = e => reject(e.target.error);
    resolve(fn(t.objectStore(store)));
  }));
}

function reqToPromise(req) {
  return new Promise((res, rej) => {
    req.onsuccess = e => res(e.target.result);
    req.onerror = e => rej(e.target.error);
  });
}

// ── Settings ──────────────────────────────────────────────────────────────────
const DB = {
  settings: {
    get: key => tx('settings', 'readonly', s => reqToPromise(s.get(key))).then(r => r?.value),
    set: (key, value) => tx('settings', 'readwrite', s => reqToPromise(s.put({ key, value }))),
    getAll: () => tx('settings', 'readonly', s => reqToPromise(s.getAll())).then(rows =>
      Object.fromEntries(rows.map(r => [r.key, r.value]))
    ),
  },

  // ── Programs ───────────────────────────────────────────────────────────────
  programs: {
    save: program => tx('programs', 'readwrite', s => reqToPromise(s.put(program))),
    get: id => tx('programs', 'readonly', s => reqToPromise(s.get(id))),
    getAll: () => tx('programs', 'readonly', s => reqToPromise(s.getAll())),
    delete: id => tx('programs', 'readwrite', s => reqToPromise(s.delete(id))),
  },

  // ── Workout Logs ──────────────────────────────────────────────────────────
  logs: {
    save: log => tx('workoutLogs', 'readwrite', s => reqToPromise(s.put(log))),
    get: id => tx('workoutLogs', 'readonly', s => reqToPromise(s.get(id))),
    getAll: () => tx('workoutLogs', 'readonly', s => reqToPromise(s.getAll())),
    // Get the most recent log for a specific program day
    getLastForDay: async (programDayId) => {
      const all = await tx('workoutLogs', 'readonly', s => reqToPromise(s.getAll()));
      const matching = all.filter(l => l.programDayId === programDayId);
      if (!matching.length) return null;
      return matching.sort((a, b) => b.date.localeCompare(a.date))[0];
    },
    // Get logs within a date range
    getRange: async (fromDate, toDate) => {
      const all = await tx('workoutLogs', 'readonly', s => reqToPromise(s.getAll()));
      return all.filter(l => l.date >= fromDate && l.date <= toDate)
                .sort((a, b) => b.date.localeCompare(a.date));
    },
    delete: id => tx('workoutLogs', 'readwrite', s => reqToPromise(s.delete(id))),
  },

  // ── Helpers ───────────────────────────────────────────────────────────────
  getActiveProgram: async () => {
    const id = await DB.settings.get('activeProgramId');
    if (!id) return null;
    return DB.programs.get(id);
  },

  setActiveProgram: async (programId) => {
    await DB.settings.set('activeProgramId', programId);
  },

  getSchedule: () => DB.settings.get('schedule'),
  setSchedule: schedule => DB.settings.set('schedule', schedule),

  getApiKey: () => DB.settings.get('apiKey'),
  setApiKey: key => DB.settings.set('apiKey', key),

  // ── Utils ─────────────────────────────────────────────────────────────────
  generateId: () => Date.now().toString(36) + Math.random().toString(36).slice(2, 7),

  todayStr: () => {
    const override = localStorage.getItem('gymDevDay');
    if (override) {
      // Return a fake date string that matches the simulated weekday
      // Use a fixed reference week so logs don't collide with real ones
      const dayIndex = ['sun','mon','tue','wed','thu','fri','sat'].indexOf(override);
      const d = new Date('2099-01-01'); // far future — won't clash with real logs
      const offset = (dayIndex - d.getDay() + 7) % 7;
      d.setDate(d.getDate() + offset);
      return d.toISOString().slice(0, 10);
    }
    return new Date().toISOString().slice(0, 10);
  },

  dayOfWeek: () => {
    const override = localStorage.getItem('gymDevDay');
    if (override) return override;
    return ['sun','mon','tue','wed','thu','fri','sat'][new Date().getDay()];
  },

  // ── Dev helpers ───────────────────────────────────────────────────────────
  dev: {
    isEnabled: () => localStorage.getItem('gymDevMode') === 'true',
    setDay: day => {
      if (day) localStorage.setItem('gymDevDay', day);
      else localStorage.removeItem('gymDevDay');
    },
    getDay: () => localStorage.getItem('gymDevDay') || '',
    setMode: on => {
      localStorage.setItem('gymDevMode', on ? 'true' : 'false');
      if (!on) localStorage.removeItem('gymDevDay');
    },
    setMockAI: on => localStorage.setItem('gymMockAI', on ? 'true' : 'false'),
    isMockAI: () => localStorage.getItem('gymMockAI') === 'true',
  },
};
